              <p>${sheetApiConfigured() ? 'เชื่อมต่อ Google Sheets Web App พร้อมบันทึกลงชีต' : 'ยังไม่ได้ตั้งค่า endpoint สำหรับเขียนข้อมูล: เปิดด้วย ?api=WEB_APP_URL หลัง deploy Code.gs'}</p>
